SELECT n.notice_code AS noticeCode, n.project_code AS projectCode, p.project_name AS projectName, n.title AS title, n.user_code AS userCode, u.name AS creatorName, n.created_at AS createdAt, n.updated_at AS updatedAt, n.file_code AS fileCode FROM notices n JOIN projects p ON p.project_code = n.project_code LEFT JOIN users u ON u.user_code = n.user_code WHERE 1 = 1
AND n.project_code = #{cond.projectCode}
AND n.project_code IN
#{code}
AND p.status IN ('OD1', 'OD3')
AND (
( n.project_code IN
#{code}
AND p.status IN ('OD1', 'OD3') )
OR
( n.project_code IN
#{code}
AND p.status = 'OD1' )
)
ORDER BY n.notice_code DESC

SELECT n.notice_code AS noticeCode, n.project_code AS projectCode, p.project_name AS projectName, p.status AS projectStatus, n.title AS title, n.content AS content, n.user_code AS userCode, u.name AS creatorName, n.created_at AS createdAt, n.updated_at AS updatedAt, n.file_code AS fileCode,
d.original_name AS originalName, d.uploaded_at AS uploadedAt, d.path AS filePath FROM notices n JOIN projects p ON p.project_code = n.project_code LEFT JOIN users u ON u.user_code = n.user_code LEFT JOIN ( SELECT a.file_code, ad.original_name, ad.path, a.uploaded_at FROM attachments a JOIN attachments_detail ad ON ad.file_code = a.file_code AND ad.is_used = 1 ) d ON d.file_code = n.file_code WHERE n.notice_code = #{noticeCode}
AND n.project_code IN
#{code}
AND p.status IN ('OD1', 'OD3')
AND (
( n.project_code IN
#{code}
AND p.status IN ('OD1', 'OD3') )
OR
( n.project_code IN
#{code}
AND p.status = 'OD1' )
)
